void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("MaracaiboMayorPhantom_1");			link.l1 = StringFromKey("MaracaiboMayorPhantom_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("MaracaiboMayorPhantom_3");			link.l1 = StringFromKey("MaracaiboMayorPhantom_4");			link.l1.go = "exit";			NextDiag.TempNode = "2";			AddDialogExitQuest("FL5_s29");		break;		case "2":			if (CheckAttribute(pchar, "MainQuest") && pchar.MainQuest == "FL5_s38")			{				dialog.text = StringFromKey("MaracaiboMayorPhantom_5");				link.l1 = StringFromKey("MaracaiboMayorPhantom_6");				link.l1.go = "3";				break;			}			dialog.text = StringFromKey("MaracaiboMayorPhantom_7");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "2";		break;		case "3":			dialog.text = StringFromKey("MaracaiboMayorPhantom_8");			link.l1 = StringFromKey("MaracaiboMayorPhantom_9");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("MaracaiboMayorPhantom_10");			link.l1 = StringFromKey("MaracaiboMayorPhantom_11");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("MaracaiboMayorPhantom_12");			link.l1 = StringFromKey("MaracaiboMayorPhantom_13");			link.l1.go = "exit";			AddDialogExitQuest("FL5_s40");		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}